package cn.mtplayer.tv;
import android.view.View;import android.view.ViewGroup;import android.widget.ImageView;import android.widget.LinearLayout;import android.widget.TextView;import androidx.annotation.NonNull;import androidx.recyclerview.widget.RecyclerView;import com.bumptech.glide.Glide;import java.util.List;import cn.mtplayer.core.model.MediaItem;
public final class TvMediaAdapter extends RecyclerView.Adapter<TvMediaAdapter.Holder>{public interface Listener{void open(MediaItem item);}private final List<MediaItem> items;private final Listener listener;public TvMediaAdapter(List<MediaItem> values,Listener listener){items=values;this.listener=listener;}@NonNull @Override public Holder onCreateViewHolder(@NonNull ViewGroup p,int t){LinearLayout card=new LinearLayout(p.getContext());card.setOrientation(LinearLayout.VERTICAL);card.setPadding(TvUi.dp(p.getContext(),7),TvUi.dp(p.getContext(),7),TvUi.dp(p.getContext(),7),TvUi.dp(p.getContext(),10));card.setFocusable(true);card.setClickable(true);card.setLayoutParams(new ViewGroup.LayoutParams(TvUi.dp(p.getContext(),190),ViewGroup.LayoutParams.WRAP_CONTENT));ImageView poster=new ImageView(p.getContext());poster.setScaleType(ImageView.ScaleType.CENTER_CROP);card.addView(poster,new LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,TvUi.dp(p.getContext(),266)));TextView title=TvUi.title(p.getContext(),"",17);title.setMaxLines(2);card.addView(title,TvUi.matchWrap());TextView meta=TvUi.text(p.getContext(),"");meta.setTextSize(13);card.addView(meta,TvUi.matchWrap());card.setOnFocusChangeListener((v,f)->{TvUi.style(v,TvUi.BG,f);v.animate().scaleX(f?1.06f:1f).scaleY(f?1.06f:1f).translationY(f?-TvUi.dp(v.getContext(),6):0).setDuration(140).start();});return new Holder(card,poster,title,meta);}@Override public void onBindViewHolder(@NonNull Holder h,int pos){MediaItem i=items.get(pos);h.title.setText(i.name);h.meta.setText(i.siteName+"  "+i.remarks);Glide.with(h.poster).load(i.poster).centerCrop().into(h.poster);h.itemView.setOnClickListener(v->listener.open(i));}@Override public int getItemCount(){return items.size();}static final class Holder extends RecyclerView.ViewHolder{final ImageView poster;final TextView title,meta;Holder(View v,ImageView p,TextView t,TextView m){super(v);poster=p;title=t;meta=m;}}}
